{
  "mode": "Indexed",
  "displayName": "Add or correct cost-center tag on resources",
  "parameters": {
    "costCenter": {
      "type": "String",
      "metadata": { "displayName": "Cost center value" }
    }
  },
  "policyRule": {
    "if": {
      "anyOf": [
        { "field": "tags['cost-center']", "exists": "false" },
        { "field": "tags['cost-center']", "notEquals": "[parameters('costCenter')]" }
      ]
    },
    "then": {
      "effect": "modify",
      "details": {
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "operations": [{
          "operation": "addOrReplace",
          "field": "tags['cost-center']",
          "value": "[parameters('costCenter')]"
        }]
      }
    }
  }
}

// A common CAF pattern: inherit the cost-center tag from the resource group
{
  "mode": "Indexed",
  "displayName": "Inherit cost-center tag from resource group",
  "policyRule": {
    "if": {
      "allOf": [
        { "value": "[resourceGroup().tags['cost-center']]", "notEquals": "" },
        { "field": "tags['cost-center']", "exists": "false" }
      ]
    },
    "then": {
      "effect": "modify",
      "details": {
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "operations": [{
          "operation": "add",
          "field": "tags['cost-center']",
          "value": "[resourceGroup().tags['cost-center']]"
        }]
      }
    }
  }
}

// Remove a tag that should never be on resources (e.g. a PII-containing tag)
{
  "mode": "Indexed",
  "displayName": "Remove disallowed tag: employee-email",
  "policyRule": {
    "if": {
      "field": "tags['employee-email']",
      "exists": "true"
    },
    "then": {
      "effect": "modify",
      "details": {
        "roleDefinitionIds": [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ],
        "operations": [{
          "operation": "remove",
          "field": "tags['employee-email']"
        }]
      }
    }
  }
}

# modify-tag-policy.tf

resource "azurerm_policy_definition" "add_cost_center_tag" {
  name         = "add-cost-center-tag"
  policy_type  = "Custom"
  mode         = "Indexed"
  display_name = "Add or correct cost-center tag on resources"
  management_group_id = var.corp_mg_id

  parameters = jsonencode({
    costCenter = {
      type     = "String"
      metadata = { displayName = "Cost Center Value" }
    }
  })

  policy_rule = jsonencode({
    if = {
      anyOf = [
        { field = "tags['cost-center']", exists = "false" },
        { field = "tags['cost-center']", notEquals = "[parameters('costCenter')]" }
      ]
    }
    then = {
      effect = "modify"
      details = {
        roleDefinitionIds = [
          "/providers/Microsoft.Authorization/roleDefinitions/b24988ac-6180-42a0-ab88-20f7382dd24c"
        ]
        operations = [{
          operation = "addOrReplace"
          field     = "tags['cost-center']"
          value     = "[parameters('costCenter')]"
        }]
      }
    }
  })
}

resource "azurerm_management_group_policy_assignment" "add_cost_center_tag" {
  name                 = "add-cost-center-tag"
  display_name         = "Add or correct cost-center tag on resources"
  policy_definition_id = azurerm_policy_definition.add_cost_center_tag.id
  management_group_id  = var.corp_mg_id

  identity {
    type = "SystemAssigned"
  }
  location = "eastus2"

  parameters = jsonencode({
    costCenter = { value = "unassigned" }
  })
}

# Grant the managed identity Contributor at the MG scope
resource "azurerm_role_assignment" "modify_policy_mi" {
  scope                = var.corp_mg_id
  role_definition_name = "Contributor"
  principal_id         = azurerm_management_group_policy_assignment.add_cost_center_tag.identity[0].principal_id
  depends_on           = [azurerm_management_group_policy_assignment.add_cost_center_tag]
}

{
  "mode": "Indexed",
